<style>
  :root{
    --sky:#5ec9ff; --sky2:#bdf0ff; --leaf:#36c24a; --leaf2:#1f8f37;
    --orange:#ff7a2b; --orange2:#ffb155; --gold:#ffcf3a; --teal:#36e0ff; --red:#ff3b3b;
  }
  *{box-sizing:border-box;-webkit-tap-highlight-color:transparent;}
  html,body{margin:0;height:100%;overflow:hidden;background:#9fe6ff;
    font-family:"Trebuchet MS",system-ui,Segoe UI,sans-serif;color:#fff;
    user-select:none;}
  #wrap{position:fixed;inset:0;overflow:hidden;
    background:linear-gradient(180deg,#2f9fe0 0%, #6cc9f5 38%, #bdeeff 72%, #e9fff0 100%);}
  canvas#scene{display:block;width:100%;height:100%;touch-action:none;}

  /* Modernes Grading: weiche Vignette + minimaler warmer Glanz (kein CRT mehr) */
  #grade{position:absolute;inset:0;pointer-events:none;z-index:5;
    background:
      radial-gradient(135% 110% at 50% 38%, transparent 52%, rgba(8,30,40,.55) 100%);
    mix-blend-mode:multiply;opacity:.55;}
  /* leichte Sättigungs-/Kontrast-Anhebung übers ganze Bild (modern, knackig) */
  #grade::after{content:"";position:absolute;inset:0;
    background:linear-gradient(180deg, rgba(255,200,120,.06), rgba(40,120,90,.05));
    mix-blend-mode:overlay;}
  #flash{position:absolute;inset:0;pointer-events:none;z-index:6;opacity:0;
    background:radial-gradient(circle at 50% 50%, rgba(255,255,255,.7), transparent 60%);
    transition:opacity .08s ease-out;}

  /* HUD */
  #hud{position:absolute;top:0;left:0;right:0;z-index:7;display:flex;
    justify-content:space-between;align-items:flex-start;
    padding:12px 16px;pointer-events:none;}
  .col{display:flex;flex-direction:column;line-height:1.05;}
  .col.mid{align-items:center;} .col.right{align-items:flex-end;}
  .lab{font-size:9px;color:#0b5a2e;letter-spacing:3px;font-weight:bold;
    text-shadow:0 1px 0 rgba(255,255,255,.5);}
  .val{font-size:22px;font-weight:900;color:#fff;
    text-shadow:0 0 8px rgba(20,120,60,.4),2px 2px 0 #1f8f37, -1px -1px 0 #0b5a2e;}
  .col.mid .val{color:var(--gold);text-shadow:0 0 10px rgba(255,180,40,.6),2px 2px 0 #b06a00;}
  #coinrow{display:flex;align-items:center;gap:6px;}
  #coinrow .ic{width:16px;height:16px;border-radius:50% 50% 50% 50%;
    background:radial-gradient(circle at 60% 35%, #fff0a0, #ffb02b 55%, #d4570f);
    box-shadow:0 0 8px rgba(255,170,40,.85);}
  /* aktive Power-Ups */
  #pups{position:absolute;top:54px;left:16px;z-index:7;display:flex;gap:8px;pointer-events:none;}
  .pup{display:flex;align-items:center;gap:5px;font-size:11px;font-weight:bold;
    padding:5px 9px;border-radius:20px;background:rgba(10,60,40,.6);
    border:1px solid rgba(255,255,255,.35);color:#eafff0;backdrop-filter:blur(2px);}
  .pup .em{font-size:14px;}
  .pup b{color:#fff;}

  /* Overlays */
  #ov{position:absolute;inset:0;z-index:8;display:flex;flex-direction:column;
    align-items:center;justify-content:center;text-align:center;gap:14px;
    background:rgba(8,40,50,.55);backdrop-filter:blur(3px);padding:22px;}
  #ov.hide{display:none;}
  .logo{font-size:min(13vw,60px);font-weight:900;letter-spacing:2px;line-height:.9;
    background:linear-gradient(180deg,#fff1a8,#ffb02b 50%,#ff5d1a);
    -webkit-background-clip:text;background-clip:text;color:transparent;
    filter:drop-shadow(2px 5px 0 #8a3208) drop-shadow(0 0 18px rgba(255,160,40,.5));}
  .logo small{display:block;font-size:min(3vw,13px);letter-spacing:7px;font-weight:700;
    color:#eafff0;-webkit-text-fill-color:#eafff0;margin-top:8px;
    filter:drop-shadow(0 1px 2px rgba(0,40,20,.6));}
  .sub{font-size:14px;color:#eafff0;max-width:360px;line-height:1.55;
    text-shadow:0 1px 3px rgba(0,30,15,.7);}
  .big{font-size:30px;font-weight:900;color:var(--gold);text-shadow:0 0 18px rgba(255,180,40,.6);}
  .stat{display:flex;gap:28px;margin:2px 0;}
  .stat div{display:flex;flex-direction:column;}
  .stat .n{font-size:24px;font-weight:900;color:#fff;text-shadow:0 2px 0 #1f8f37;}
  .stat .l{font-size:10px;letter-spacing:2px;color:#cffbe0;font-weight:bold;}
  .btn{appearance:none;border:none;cursor:pointer;font-weight:800;
    font-family:inherit;letter-spacing:1px;color:#2a0c04;
    background:linear-gradient(180deg,#ffe08a,var(--orange));
    padding:14px 34px;font-size:17px;border-radius:30px;
    box-shadow:0 5px 0 #9c4410,0 8px 22px rgba(255,120,40,.4);}
  .btn:active{transform:translateY(3px);box-shadow:0 2px 0 #9c4410;}
  .hintline{font-size:11px;color:#dffaea;max-width:380px;line-height:1.7;
    text-shadow:0 1px 2px rgba(0,30,15,.7);}
  .newrec{font-size:13px;font-weight:bold;color:var(--gold);letter-spacing:2px;
    text-shadow:0 0 12px rgba(255,200,60,.8);}

  /* Charakter-Auswahl */
  #charsel{display:flex;gap:14px;margin:4px 0 2px;}
  #charsel.hide{display:none;}
  .char{cursor:pointer;width:118px;padding:10px 10px 12px;border-radius:16px;
    background:rgba(10,55,40,.5);border:2px solid rgba(255,255,255,.25);
    display:flex;flex-direction:column;align-items:center;gap:6px;
    transition:transform .12s ease, border-color .12s ease, background .12s ease;}
  .char:hover{transform:translateY(-2px);}
  .char:hover .face{transform:scale(1.04);}
  .char.sel{border-color:var(--gold);background:rgba(255,180,40,.22);
    box-shadow:0 0 18px rgba(255,180,40,.4);}
  .char .face{width:92px;height:92px;border-radius:14px;position:relative;overflow:hidden;
    background-size:cover;background-position:50% 16%;background-repeat:no-repeat;
    box-shadow:inset 0 0 0 2px rgba(0,0,0,.28), inset 0 -22px 26px rgba(0,40,20,.45);
    transition:transform .12s ease;}
  .char .nm{font-size:13px;font-weight:900;letter-spacing:1px;color:#fff;
    text-shadow:0 1px 2px rgba(0,30,15,.8);}
  .char .ro{font-size:9px;letter-spacing:1px;color:#cffbe0;font-weight:bold;}

  /* Top-Buttons (Pause/Ton) */
  #topbtns{position:absolute;top:50px;right:14px;z-index:7;display:flex;gap:8px;}
  .tb{pointer-events:auto;border:none;border-radius:12px;background:rgba(10,55,40,.8);
    color:#eafff0;font-size:14px;font-weight:bold;padding:8px 11px;
    box-shadow:0 4px 0 #07301f;cursor:pointer;}
  .tb:active{transform:translateY(3px);box-shadow:0 1px 0 #07301f;}

  /* Mobile-Steuerung */
  #touch{position:absolute;inset:0;z-index:6;display:none;}
  @media (max-width:820px){ #touch{display:block;} }
  #foot{position:absolute;bottom:6px;left:0;right:0;z-index:7;text-align:center;
    font-size:10px;color:#bfe9d4;pointer-events:none;text-shadow:0 1px 2px rgba(0,30,15,.6);}
  #loaderr{position:absolute;inset:0;z-index:9;display:none;align-items:center;
    justify-content:center;text-align:center;padding:30px;color:#103a28;
    background:rgba(200,240,255,.95);font-size:15px;line-height:1.6;}

  /* ── CrazyFamily Highscore-Overlay (globale Top 10 via highscores.php) ── */
  #funznav{ pointer-events:none; }
  #funznav a, #funznav button{ pointer-events:auto; }
  #boardBtn{ background:none; border:none; font:inherit; font-weight:bold;
    color:#ffd23f; cursor:pointer; text-shadow:0 0 8px rgba(255,210,63,.6); }
  #backToFunzone{ color:#B6FF00; text-decoration:none; font-weight:bold;
    text-shadow:0 0 8px rgba(182,255,0,.6); }
  #backToFunzone:hover, #backToFunzone:focus-visible, #boardBtn:hover{ text-decoration:underline; }
  #cfBoard{ position:fixed; inset:0; z-index:99999; display:flex;
    align-items:center; justify-content:center; background:rgba(6,4,10,.82);
    font-family:"Trebuchet MS",system-ui,sans-serif; }
  #cfBoard[hidden]{ display:none; }
  #cfBoard .lb-card{ background:#161b26; border:3px solid #2a2f3a; border-radius:10px;
    padding:18px 20px; width:min(92vw,360px); max-height:86vh; overflow:auto;
    color:#EDEDED; text-align:left;
    box-shadow:0 0 24px rgba(255,62,165,.35),0 12px 40px rgba(0,0,0,.7); }
  #cfBoard h2{ margin:0 0 10px; font-size:15px; letter-spacing:1px; color:#ffd36b; }
  #cfBoard #lbResult{ margin:0 0 10px; font-size:13px; }
  #cfBoard #lbResult strong{ color:#B6FF00; }
  #cfBoard #lbSubmitRow{ display:flex; gap:8px; margin:0 0 12px; }
  #cfBoard #lbNick{ flex:1; min-width:0; background:#0B0E14; border:2px solid #3a4150;
    border-radius:8px; color:#fff; padding:8px 10px; font-size:14px; }
  #cfBoard #lbNick:focus{ outline:none; border-color:#FF3EA5; }
  #cfBoard .lb-btn{ background:#FF3EA5; border:none; border-radius:8px; color:#fff;
    font-weight:bold; font-size:13px; padding:8px 14px; cursor:pointer;
    box-shadow:0 3px 0 #8a1f5c; }
  #cfBoard .lb-btn:active{ transform:translateY(2px); box-shadow:0 1px 0 #8a1f5c; }
  #cfBoard .lb-btn[disabled]{ opacity:.6; cursor:default; }
  #cfBoard .lb-btn--ghost{ background:#3a4150; box-shadow:0 3px 0 #1e2330; }
  #cfBoard #lbList{ list-style:none; margin:0 0 14px; padding:0; font-size:13px; }
  #cfBoard #lbList li{ display:flex; gap:8px; padding:5px 2px;
    border-bottom:1px solid rgba(255,255,255,.07); }
  #cfBoard .lb-rank{ color:#7b8499; width:1.6em; }
  #cfBoard .lb-name{ flex:1; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
  #cfBoard .lb-score{ color:#ffd23f; font-variant-numeric:tabular-nums; }
  #cfBoard .lb-empty{ color:#7b8499; padding:6px 2px; }
  #cfBoard .lb-actions{ display:flex; justify-content:flex-end; }
</style>
</head>
<body>
<div id="wrap">
  <canvas id="scene"></canvas>
