  <div id="hud">
    <div class="col"><span class="lab">SCORE</span><span class="val" id="score">0</span></div>
    <div class="col mid"><span class="lab">REKORD</span><span class="val" id="hi">0</span></div>
    <div class="col right"><span class="lab">FRÜCHTE</span>
      <span id="coinrow"><span class="ic"></span><span class="val" id="coins">0</span></span></div>
  </div>
  <div id="pups"></div>

  <div id="topbtns">
    <button class="tb" id="pauseBtn">❚❚</button>
    <button class="tb" id="soundBtn">🔊</button>
  </div>

  <div id="touch"></div>

  <div id="ov">
    <div class="logo">CRAZY&nbsp;RUSH<small>CRAZYFAMILY ARCADE</small></div>
    <div class="sub" id="ovsub">Renn so weit du kannst durch den Dschungel der CrazyFamily-Insel – weiche aus, spring über Kisten, rutsch unter Stämmen durch und sammle leuchtende Früchte!</div>
    <div id="charsel"></div>
    <button class="btn" id="startBtn">▶ LOSLAUFEN</button>
    <div class="hintline" id="ovhint">⌨ ← → Spur wechseln · ↑ / Leertaste springen · ↓ rutschen · P Pause · M Ton<br>📱 Wischen: links/rechts/hoch/runter · Tippen = Sprung</div>
  </div>

  <div id="foot"><span id="funznav"><button type="button" id="boardBtn">🏆 Bestenliste</button> · CrazyFamily Rush · <a id="backToFunzone" href="/pages/games.php">← Zurück zur Fun-Zone</a></span></div>
  <div id="loaderr">3D-Engine konnte nicht geladen werden.<br>Bitte mit Internetverbindung neu laden.</div>
</div>

<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script src="https://unpkg.com/three@0.128.0/examples/js/loaders/GLTFLoader.js"></script>
<script src="https://unpkg.com/three@0.128.0/examples/js/loaders/DRACOLoader.js"></script>
<!-- In Blender gebautes Helden-Modell (GLB, base64). Wird via GLTFLoader geladen;
     fällt das aus (offline), greift der prozedurale Held als Fallback. -->
<script id="hero_kevin" type="application/octet-stream"></script>
<script id="hero_alex" type="application/octet-stream"></script>
<script id="jungledata" type="application/octet-stream"></script>
<script id="obstacledata" type="application/octet-stream"></script>
<script>
"use strict";
/* =========================================================================
   CRAZYFAMILY RUSH — eigenständiger 3D-Endless-Runner im CrazyFamily-Look
   Tropen-/Dschungel-Insel (Crash-Bandicoot-Vibe), helle moderne Grafik.
   Komplett eigener Code & prozedural erzeugte Grafik – inspiriert vom Genre,
   aber ohne Original-Code, -Modelle, -Texturen oder -Namen.
   Helden = CrazyFamily-Charaktere "Kevin" (oranger Hoodie) & "Alex" (dunkler).
   ========================================================================= */
(function(){
if(typeof THREE==="undefined"){ document.getElementById("loaderr").style.display="flex"; return; }

/* ---------- DOM ---------- */
const $=id=>document.getElementById(id);
const elScore=$("score"), elHi=$("hi"), elCoins=$("coins"), elPups=$("pups");
const ov=$("ov"), ovsub=$("ovsub"), ovhint=$("ovhint"), startBtn=$("startBtn"), charsel=$("charsel");
const flash=$("flash");

/* ---------- Konstanten ---------- */
const LANE_X=[-2.3,0,2.3];
const HI_KEY="crazyrush_hi_v2";
const CHAR_KEY="crazyrush_char_v1";
const isMobile=matchMedia("(max-width:820px)").matches || ("ontouchstart" in window);

/* ---------- Charaktere ---------- */
const CHARS={
  kevin:{ name:"KEVIN", role:"GRÜNER HOODIE",
    hoodie:0xff7e2c, hoodieDark:0xc9531a, cap:0x18171c, capPeak:0x101015,
    skin:0xe2a274, hood:0xff8a3c },
  alex:{ name:"ALEX", role:"ORANGER HOODIE",
    hoodie:0x3b3f48, hoodieDark:0x23262d, cap:0xff7e2c, capPeak:0x274b9a,
    skin:0xdb9a68, hood:0x4a4f59 },
};
/* Startscreen-Portraits aus den echten 3D-Modellen gerendert
   (tools/blender/make_char_portraits.py). */
const PORTRAITS={
  kevin:"data:image/png;base64,",
  alex:"data:image/png;base64,",
};

/* ---------- Renderer / Szene / Kamera ---------- */
const canvas=$("scene");
const renderer=new THREE.WebGLRenderer({canvas,antialias:!isMobile,alpha:false,powerPreference:"high-performance"});
renderer.shadowMap.enabled=true;
renderer.shadowMap.type=THREE.PCFSoftShadowMap;
renderer.outputEncoding=THREE.sRGBEncoding;
renderer.toneMapping=THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure=0.92;

const scene=new THREE.Scene();
const SKY_HORIZON=0x86d4f5;
scene.background=new THREE.Color(SKY_HORIZON);
scene.fog=new THREE.Fog(SKY_HORIZON, 95, isMobile?210:260);

const camera=new THREE.PerspectiveCamera(60, 1, 0.1, 600);
const camBase=new THREE.Vector3(0,5.1,9.3);
camera.position.copy(camBase);
camera.lookAt(0,1.4,-12);

/* ---------- Licht (heller Tropen-Tag) ---------- */
const hemi=new THREE.HemisphereLight(0xbfe7ff, 0x2c6e26, 1.0);  // Himmel oben / Gras unten
scene.add(hemi);
const ambient=new THREE.AmbientLight(0xffffff, 0.28); scene.add(ambient);
const sun=new THREE.DirectionalLight(0xfff0d2, 1.45);
sun.position.set(-10,22,7);
sun.castShadow=true;
sun.shadow.mapSize.set(isMobile?1024:1536, isMobile?1024:1536);
sun.shadow.camera.near=1; sun.shadow.camera.far=70;
sun.shadow.camera.left=-12; sun.shadow.camera.right=12;
sun.shadow.camera.top=18; sun.shadow.camera.bottom=-18;
sun.shadow.bias=-0.0006;
scene.add(sun);
const sunTarget=new THREE.Object3D(); scene.add(sunTarget); sun.target=sunTarget;
// kühles Himmels-Gegenlicht für Kontur
const rim=new THREE.DirectionalLight(0x9fd8ff, 0.4); rim.position.set(8,10,-12); scene.add(rim);

/* ---------- Himmel: Gradient-Dome + Wolken ---------- */
function makeSkyTexture(){
  const c=document.createElement("canvas"); c.width=16; c.height=256;
  const x=c.getContext("2d");
  const g=x.createLinearGradient(0,0,0,256);
  g.addColorStop(0.0,"#0f6ec6");   // Zenit (kräftiger)
  g.addColorStop(0.45,"#2f9ae0");
  g.addColorStop(0.8,"#7fc8ef");
  g.addColorStop(1.0,"#bfe8fb");   // Horizont
  x.fillStyle=g; x.fillRect(0,0,16,256);
  const t=new THREE.CanvasTexture(c); t.encoding=THREE.sRGBEncoding; return t;
}
const skyDome=new THREE.Mesh(
  new THREE.SphereGeometry(420,24,16),
  new THREE.MeshBasicMaterial({map:makeSkyTexture(),side:THREE.BackSide,fog:false,depthWrite:false})
);
scene.add(skyDome);

function makeCloudTexture(){
  const c=document.createElement("canvas"); c.width=c.height=128; const x=c.getContext("2d");
  for(let i=0;i<22;i++){
    const cx=64+(Math.random()-.5)*70, cy=64+(Math.random()-.5)*44, r=14+Math.random()*26;
    const g=x.createRadialGradient(cx,cy,0,cx,cy,r);
    g.addColorStop(0,"rgba(255,255,255,.95)"); g.addColorStop(1,"rgba(255,255,255,0)");
    x.fillStyle=g; x.beginPath(); x.arc(cx,cy,r,0,7); x.fill();
  }
  return new THREE.CanvasTexture(c);
}
const cloudTex=makeCloudTexture();
const clouds=[];
for(let i=0;i<10;i++){
  const m=new THREE.Mesh(new THREE.PlaneGeometry(60,30),
    new THREE.MeshBasicMaterial({map:cloudTex,transparent:true,opacity:.9,fog:false,depthWrite:false}));
  m.position.set((Math.random()-.5)*340, 60+Math.random()*70, -120-Math.random()*220);
  m.userData.drift=2+Math.random()*4;
  scene.add(m); clouds.push(m);
}

/* ---------- Straße (Tropen-Steinpfad, scrollend) ---------- */
function makeRoadTexture(){
  const c=document.createElement("canvas"); c.width=256; c.height=1024;
  const x=c.getContext("2d");
  // Gleichmäßiger SAND-/Erdpfad (Dschungel). BEWUSST OHNE Querfugen/Striche/feine Körnung:
  // nur durchgehende Längs-Elemente scrollen "in sich" -> Bewegung praktisch unsichtbar;
  // Tempo liest man an den Objekten ab (Subway-Surfers-Prinzip).
  const g=x.createLinearGradient(0,0,0,1024);
  g.addColorStop(0,"#cbb184"); g.addColorStop(1,"#bb9c69");
  x.fillStyle=g; x.fillRect(0,0,256,1024);
  // sehr dezente, NIEDERfrequente Erdflecken (große, blasse Patches -> kaum Bewegungsreiz)
  for(let i=0;i<22;i++){
    x.fillStyle=`rgba(${120+Math.random()*40|0},${95+Math.random()*35|0},${55+Math.random()*25|0},${.06+Math.random()*.07})`;
    x.beginPath(); x.arc(Math.random()*256,Math.random()*1024,30+Math.random()*70,0,7); x.fill();
  }
  // weiche, DURCHGEHENDE Trampelspuren (zwei helle Längsbänder) -> deutet "Weg" an, ruhig
  function rut(px){
    const grd=x.createLinearGradient(px-22,0,px+22,0);
    grd.addColorStop(0,"rgba(210,190,150,0)"); grd.addColorStop(.5,"rgba(214,194,150,.35)"); grd.addColorStop(1,"rgba(210,190,150,0)");
    x.fillStyle=grd; x.fillRect(px-22,0,44,1024);
  }
  rut(256*0.34); rut(256*0.66);
  // erdig-grasige Ränder (durchgehend)
  x.fillStyle="#7d6a3c"; x.fillRect(0,0,16,1024); x.fillRect(240,0,16,1024);
  x.fillStyle="#5f7a36"; x.fillRect(0,0,7,1024); x.fillRect(249,0,7,1024); // Gras-Saum
  const t=new THREE.CanvasTexture(c);
  t.wrapS=THREE.RepeatWrapping; t.wrapT=THREE.RepeatWrapping;
  t.repeat.set(1,2); t.anisotropy=4; t.encoding=THREE.sRGBEncoding;
  return t;
}
const roadTex=makeRoadTexture();
const roadMat=new THREE.MeshStandardMaterial({map:roadTex, roughness:.95, metalness:.0});
const road=new THREE.Mesh(new THREE.PlaneGeometry(7.5, 360), roadMat);
road.rotation.x=-Math.PI/2; road.position.set(0,0,-160); road.receiveShadow=true;
