// Gras-Seitenboden
function makeGrassTexture(){
  const c=document.createElement("canvas"); c.width=c.height=256; const x=c.getContext("2d");
  x.fillStyle="#2f9c3c"; x.fillRect(0,0,256,256);
  for(let i=0;i<5000;i++){ const g=20+Math.random()*60;
    x.fillStyle=`rgba(${20+Math.random()*30|0},${110+g|0},${30+Math.random()*30|0},${.4})`;
    x.fillRect(Math.random()*256,Math.random()*256,2,3); }
  const t=new THREE.CanvasTexture(c); t.wrapS=t.wrapT=THREE.RepeatWrapping; t.repeat.set(8,30); t.encoding=THREE.sRGBEncoding; return t;
}
const grassTex=makeGrassTexture();
