// kleiner leuchtender Pfeil (Hinweis: hoch = springen, runter = rutschen)
function makeArrow(up){
  const a=new THREE.Mesh(new THREE.ConeGeometry(0.34,0.55,4), up?M.arrowUp:M.arrowDn);
  a.rotation.y=Math.PI/4; if(!up) a.rotation.x=Math.PI;
  a.userData.arrow=true; return a;
}

/* ---------- Hoodie-Textur (CRAZY FAMILY) ---------- */
function makeHoodieTex(col){
  const c=document.createElement("canvas"); c.width=c.height=128; const x=c.getContext("2d");
  x.fillStyle="#"+col.toString(16).padStart(6,"0"); x.fillRect(0,0,128,128);
  // leichte Schattierung
  const g=x.createLinearGradient(0,0,0,128); g.addColorStop(0,"rgba(255,255,255,.12)"); g.addColorStop(1,"rgba(0,0,0,.18)");
  x.fillStyle=g; x.fillRect(0,0,128,128);
  // Kapuzen-Schnur
  x.strokeStyle="rgba(255,255,255,.5)"; x.lineWidth=3;
  x.beginPath(); x.moveTo(54,2); x.lineTo(58,30); x.stroke();
  x.beginPath(); x.moveTo(74,2); x.lineTo(70,30); x.stroke();
  // Text
  x.fillStyle="#ffffff"; x.textAlign="center"; x.font="900 21px Arial Black, Arial, sans-serif";
  x.shadowColor="rgba(0,0,0,.35)"; x.shadowBlur=2;
  x.fillText("CRAZY",64,78); x.fillText("FAMILY",64,100);
  const t=new THREE.CanvasTexture(c); t.encoding=THREE.sRGBEncoding; return t;
}
// reines CRAZY-FAMILY-Logo (transparent) für das Rücken-Decal am 3D-Modell
function makeLogoTex(){
  const c=document.createElement("canvas"); c.width=256; c.height=160; const x=c.getContext("2d");
  x.clearRect(0,0,256,160);
  x.fillStyle="#ffffff"; x.textAlign="center";
  x.shadowColor="rgba(0,0,0,.45)"; x.shadowBlur=4;
  x.font="900 52px Arial Black, Arial, sans-serif"; x.fillText("CRAZY",128,66);
  x.fillText("FAMILY",128,126);
  const t=new THREE.CanvasTexture(c); t.encoding=THREE.sRGBEncoding; return t;
}

/* ---------- Held (CrazyFamily-Charakter) ---------- */
function buildHero(cfg){
  const g=new THREE.Group();
  const skin =new THREE.MeshStandardMaterial({color:cfg.skin,roughness:.6});
  const hood =new THREE.MeshStandardMaterial({color:cfg.hoodie,roughness:.7});
  const hoodD=new THREE.MeshStandardMaterial({color:cfg.hoodieDark,roughness:.75});
  const pants=new THREE.MeshStandardMaterial({color:0x39506e,roughness:.85});      // Jeans
  const pantsD=new THREE.MeshStandardMaterial({color:0x2a3d56,roughness:.9});
  const cap  =new THREE.MeshStandardMaterial({color:cfg.cap,roughness:.7});
  const capP =new THREE.MeshStandardMaterial({color:cfg.capPeak,roughness:.7});
  const beard=new THREE.MeshStandardMaterial({color:0x3a2616,roughness:.9});
  const eye  =new THREE.MeshStandardMaterial({color:0x9fe8ff,emissive:0x5ad0ff,emissiveIntensity:2.4});
  const shoe =new THREE.MeshStandardMaterial({color:0xf2f2f2,roughness:.6});
  const shoeS=new THREE.MeshStandardMaterial({color:0xff7a2b,roughness:.6});

  // Hoodie-Torso mit CRAZY-FAMILY-Front (Textur nur vorne, +z = Index 4)
  const hoodieTex=makeHoodieTex(cfg.hoodie);
  const front=new THREE.MeshStandardMaterial({map:hoodieTex,roughness:.7});
  const torsoMats=[hood,hood,hood,hoodD,front,hood];
  const torso=new THREE.Mesh(new THREE.BoxGeometry(1.06,1.15,0.62),torsoMats);
  torso.position.y=1.5; g.add(torso);
  // Brust/Schulter-Block (muskulös)
  const chest=new THREE.Mesh(new THREE.BoxGeometry(1.16,0.46,0.7),hood); chest.position.y=1.92; g.add(chest);
  // Kapuze hinten
  const hoodBack=new THREE.Mesh(new THREE.BoxGeometry(0.78,0.46,0.34),hoodD); hoodBack.position.set(0,2.06,0.22); g.add(hoodBack);
  // Hüfte / Jeans
  const hip=new THREE.Mesh(new THREE.BoxGeometry(0.86,0.42,0.58),pants); hip.position.y=0.96; g.add(hip);

  // Kopf
  const head=new THREE.Mesh(new THREE.BoxGeometry(0.66,0.64,0.62),skin); head.position.y=2.46; g.add(head);
  // Bart (unteres Gesicht)
  const beardM=new THREE.Mesh(new THREE.BoxGeometry(0.6,0.3,0.58),beard); beardM.position.set(0,2.22,0.04); g.add(beardM);
  const beardS=new THREE.Mesh(new THREE.BoxGeometry(0.66,0.22,0.62),beard); beardS.position.set(0,2.34,0); g.add(beardS); // Koteletten
  // Kappe
  const capTop=new THREE.Mesh(new THREE.BoxGeometry(0.72,0.3,0.68),cap); capTop.position.y=2.82; g.add(capTop);
  const capPeak=new THREE.Mesh(new THREE.BoxGeometry(0.66,0.09,0.4),capP); capPeak.position.set(0,2.7,-0.46); g.add(capPeak);
  const capBtn=new THREE.Mesh(new THREE.SphereGeometry(0.06,8,6),capP); capBtn.position.set(0,2.99,0); g.add(capBtn);
  // wütende Brauen (leicht schräg)
  const browL=new THREE.Mesh(new THREE.BoxGeometry(0.22,0.08,0.06),beard); browL.position.set(-0.16,2.58,-0.32); browL.rotation.z=-0.32; g.add(browL);
  const browR=browL.clone(); browR.position.x=0.16; browR.rotation.z=0.32; g.add(browR);
  // leuchtende Augen
  const eL=new THREE.Mesh(new THREE.BoxGeometry(0.15,0.11,0.05),eye); eL.position.set(-0.16,2.48,-0.32); g.add(eL);
  const eR=eL.clone(); eR.position.x=0.16; g.add(eR);

  // Arme (Pivot an Schulter)
  function arm(side){
    const grp=new THREE.Group(); grp.position.set(side*0.72,2.0,0);
    const up=new THREE.Mesh(new THREE.BoxGeometry(0.3,0.72,0.32),hood); up.position.y=-0.34; grp.add(up);
    const fore=new THREE.Mesh(new THREE.BoxGeometry(0.27,0.5,0.29),skin); fore.position.y=-0.92; grp.add(fore);
    const fist=new THREE.Mesh(new THREE.BoxGeometry(0.3,0.3,0.32),skin); fist.position.y=-1.24; grp.add(fist);
    grp.traverse(o=>{o.castShadow=true;}); g.add(grp); return grp;
  }
  // Beine (Pivot an Hüfte)
  function leg(side){
    const grp=new THREE.Group(); grp.position.set(side*0.26,0.86,0);
    const up=new THREE.Mesh(new THREE.BoxGeometry(0.34,0.74,0.36),pants); up.position.y=-0.37; grp.add(up);
    const low=new THREE.Mesh(new THREE.BoxGeometry(0.3,0.5,0.32),pantsD); low.position.y=-0.86; grp.add(low);
    const sh=new THREE.Mesh(new THREE.BoxGeometry(0.38,0.26,0.54),shoe); sh.position.set(0,-1.2,0.08); grp.add(sh);
    const st=new THREE.Mesh(new THREE.BoxGeometry(0.4,0.1,0.54),shoeS); st.position.set(0,-1.07,0.08); grp.add(st);
    grp.traverse(o=>{o.castShadow=true;}); g.add(grp); return grp;
  }
  const armL=arm(-1), armR=arm(1), legL=leg(-1), legR=leg(1);
  g.traverse(o=>{ if(o.isMesh) o.castShadow=true; });

  // Jetpack-Glut (anfangs aus)
  const flame=new THREE.Mesh(new THREE.ConeGeometry(0.28,1.1,8), new THREE.MeshBasicMaterial({color:0xffae3a,transparent:true,opacity:.9}));
  flame.position.set(0,0.7,0.55); flame.rotation.x=Math.PI; flame.visible=false; g.add(flame);

  g.userData={armL,armR,legL,legR,torso,head,flame};
  return g;
}
/* In Blender gerigte + animierte Meshy-Modelle (sobald geladen). Bis dahin prozeduraler
   Box-Held als Fallback. Pro Charakter ein eigenes, fertig texturiertes GLB. */
let gltfTemplates={};                 // {kevin:{scene,animations}, alex:{...}}
const HERO_SCALE=1.5;                 // skaliert das ~2 Einheiten hohe Meshy-Modell ins Spiel
function buildHeroGLTF(key){
  const gltf=gltfTemplates[key];
  const model=gltf.scene;
  model.traverse(o=>{ if(!o.isMesh) return;
    o.castShadow=true; o.frustumCulled=false;   // SkinnedMesh nicht fälschlich wegcullen
    (Array.isArray(o.material)?o.material:[o.material]).forEach(m=>{
      // ACES-Tonemapping für die Figur AUS, sonst bleicht das helle Tageslicht die
      // gebackene Textur aus (gleiche Gotcha wie beim Box-Helden).
      m.toneMapped=false;
    });
  });
  model.rotation.set(0,Math.PI,0);              // Gesicht WEG von der Kamera = Laufrichtung
  model.scale.setScalar(HERO_SCALE);
  model.position.y=HERO_SCALE;                  // Füße (Modell-Unterkante y≈-1) auf den Boden
  const g=new THREE.Group(); g.add(model);
  // Animations-Clips
  const mixer=new THREE.AnimationMixer(model);
  const actions={};
  (gltf.animations||[]).forEach(c=>{ actions[c.name]=mixer.clipAction(c); });
  if(actions.Run) actions.Run.play();
  // Jetpack-Glut (anfangs aus)
  const flame=new THREE.Mesh(new THREE.ConeGeometry(0.28,1.1,8),
    new THREE.MeshBasicMaterial({color:0xffae3a,transparent:true,opacity:.9}));
  flame.position.set(0,0.7,0.55); flame.rotation.x=Math.PI; flame.visible=false; g.add(flame);
  g.userData={mixer,actions,cur:null,flame};
  return g;
}
function makeHero(key){ return gltfTemplates[key] ? buildHeroGLTF(key) : buildHero(CHARS[key]); }

let heroCfgKey=localStorage.getItem(CHAR_KEY) || "kevin";
if(!CHARS[heroCfgKey]) heroCfgKey="kevin";
let hero=makeHero(heroCfgKey); scene.add(hero);
function setCharacter(key){
  if(!CHARS[key]) return;
  heroCfgKey=key; localStorage.setItem(CHAR_KEY,key);
  scene.remove(hero); hero=makeHero(key); scene.add(hero);
  hero.position.set(0,0,0);
  renderCharSel();
}
// Gerigte Blender-Modelle asynchron laden und den prozeduralen Helden ersetzen
(function loadHeroModels(){
  try{
    if(typeof THREE.GLTFLoader==="undefined") return;
    const loader=new THREE.GLTFLoader();
    if(THREE.DRACOLoader){
      const draco=new THREE.DRACOLoader();
      draco.setDecoderPath("https://unpkg.com/three@0.128.0/examples/js/libs/draco/");
      loader.setDRACOLoader(draco);
    }
    const ids={kevin:"hero_kevin", alex:"hero_alex"};
    for(const key in ids){
      const el=document.getElementById(ids[key]);
      if(!el) continue;
      const b64=(el.textContent||"").trim();
      if(b64.length<200 || b64.indexOf("__HERO")===0) continue;  // nicht eingebettet
      const bin=atob(b64), buf=new Uint8Array(bin.length);
      for(let i=0;i<bin.length;i++) buf[i]=bin.charCodeAt(i);
      loader.parse(buf.buffer, "", gltf=>{
        gltfTemplates[key]={scene:gltf.scene, animations:gltf.animations};
        if(key===heroCfgKey){ scene.remove(hero); hero=makeHero(heroCfgKey); scene.add(hero); hero.position.set(0,0,0); }
      }, ()=>{ /* Parse-Fehler -> prozeduraler Fallback bleibt */ });
    }
  }catch(e){ /* Fallback bleibt */ }
})();

/* ---------- Object-Pools (Hindernisse / Früchte / Power-Ups) ---------- */
const pools={crate:[],slide:[],wreck:[],train:[],coin:[],power:[]};
function acquire(type){ const p=pools[type]; let o=p.find(m=>!m.visible); if(!o){ o=buildObstacle(type); scene.add(o); p.push(o);} o.visible=true; return o; }
function releaseAll(){ for(const k in pools) pools[k].forEach(o=>o.visible=false); }

function buildObstacleProc(type){
  const g=new THREE.Group();
  if(type==="crate"){
    // GELBE Holzkiste — drüberspringen (Pfeil hoch)
    const box=new THREE.Mesh(new THREE.BoxGeometry(1.7,1.2,1.2),M.crate); box.position.y=0.6; g.add(box);
    // Rahmen-Kanten
    const fr=[[0,0.6,0.61],[0,0.6,-0.61]];
    for(const [px,py,pz] of fr){
      const edge=new THREE.Mesh(new THREE.BoxGeometry(1.72,0.16,0.04),M.crateEdge); edge.position.set(px,1.12,pz); g.add(edge);
      const edge2=edge.clone(); edge2.position.y=0.08; g.add(edge2);
    }
    // gelbes Achtung-Symbol vorne (zum Springen)
    const mark=new THREE.Mesh(new THREE.BoxGeometry(0.7,0.7,0.06),M.crateMark); mark.position.set(0,0.62,0.62); g.add(mark);
    const ar=makeArrow(true); ar.position.set(0,1.9,0); g.add(ar);
    g.userData.type="crate"; g.userData.halfZ=0.6; g.userData.clear="jump"; g.userData.arrowMesh=ar;
  }else if(type==="slide"){
    // CYAN Querbalken — drunter durchrutschen (Pfeil runter). Höher gelegt + GANZ cyan,
    // damit man die Lücke klar sieht und nicht optisch reinrennt (Unterkante jetzt ≈1.95).
    const beam=new THREE.Mesh(new THREE.CylinderGeometry(0.4,0.4,2.3,12),M.slideC);
    beam.rotation.z=Math.PI/2; beam.position.y=2.35; g.add(beam);
    const glow=new THREE.Mesh(new THREE.BoxGeometry(2.3,0.26,0.62),M.slideC); glow.position.y=2.05; g.add(glow);
    // Lianen die runterhängen
    for(let i=-1;i<=1;i++){ const v=new THREE.Mesh(new THREE.CylinderGeometry(0.05,0.05,0.6,6),M.vine); v.position.set(i*0.7,1.7,0.2); g.add(v); }
    const p1=new THREE.Mesh(new THREE.BoxGeometry(0.24,2.4,0.24),M.woodDark); p1.position.set(-1.08,1.2,0); g.add(p1);
    const p2=p1.clone(); p2.position.x=1.08; g.add(p2);
    const ar=makeArrow(false); ar.position.set(0,0.85,0); g.add(ar);
    g.userData.type="slide"; g.userData.halfZ=0.42; g.userData.clear="slide"; g.userData.arrowMesh=ar;
  }else if(type==="wreck"){
    // Tiki-Statue / Steinblock — Spur blockiert (ROT)
    const base=new THREE.Mesh(new THREE.BoxGeometry(1.5,0.4,1.4),M.stoneDark); base.position.y=0.2; g.add(base);
    const body=new THREE.Mesh(new THREE.BoxGeometry(1.25,1.7,1.1),M.tiki); body.position.y=1.25; g.add(body);
    const eyL=new THREE.Mesh(new THREE.BoxGeometry(0.3,0.3,0.1),M.tikiFace); eyL.position.set(-0.28,1.7,0.56); g.add(eyL);
    const eyR=eyL.clone(); eyR.position.x=0.28; g.add(eyR);
    const mouth=new THREE.Mesh(new THREE.BoxGeometry(0.7,0.3,0.1),M.tikiFace); mouth.position.set(0,1.15,0.56); g.add(mouth);
    const tooth=new THREE.Mesh(new THREE.BoxGeometry(0.12,0.18,0.12),M.stone); tooth.position.set(0,1.05,0.6); g.add(tooth);
    // rote Warn-Leiste vorne am Sockel
    const warn=new THREE.Mesh(new THREE.BoxGeometry(1.5,0.34,0.12),M.danger); warn.position.set(0,0.28,0.72); g.add(warn);
    g.userData.type="wreck"; g.userData.halfZ=0.7; g.userData.clear="dodge";
  }else if(type==="train"){
    // langer rollender Baumstamm — Spur lange blockiert
    const len=12;
    const log=new THREE.Mesh(new THREE.CylinderGeometry(1.1,1.1,len,16),M.bark); log.rotation.x=Math.PI/2; log.position.y=1.1; g.add(log);
    // Rinde-Ringe
    for(let i=0;i<6;i++){ const ring=new THREE.Mesh(new THREE.TorusGeometry(1.12,0.07,8,18),M.barkDark);
      ring.position.set(0,1.1,-len/2+1.2+i*2.1); g.add(ring); }
    // rote Warnstreifen
    const s1=new THREE.Mesh(new THREE.BoxGeometry(2.55,0.6,len),M.danger); s1.position.y=2.05; g.add(s1);
    // Schnittflächen (hell)
    const cap1=new THREE.Mesh(new THREE.CircleGeometry(1.1,16),M.wood); cap1.position.set(0,1.1,len/2+0.01); g.add(cap1);
    g.userData.type="train"; g.userData.halfZ=len/2; g.userData.clear="dodge";
  }else if(type==="coin"){
    // ROTES leuchtendes Sammel-Juwel (Kristall) — schwebt & rotiert, klar als Pickup lesbar
    const m=new THREE.Mesh(new THREE.OctahedronGeometry(0.42,0),M.fruit); m.scale.set(0.82,1.18,0.82); g.add(m);
    const core=new THREE.Mesh(new THREE.OctahedronGeometry(0.2,0),M.fruitCore); g.add(core);
    g.userData.type="coin";
  }else if(type==="power"){
    // Maske/Talisman-Power-Up
    const ball=new THREE.Mesh(new THREE.IcosahedronGeometry(0.42,0),M.neonHot); g.add(ball);
    const ring=new THREE.Mesh(new THREE.TorusGeometry(0.62,0.05,8,24),M.neon); g.add(ring);
    const lamp=new THREE.PointLight(0xffae3a,0.9,8); g.add(lamp);
    g.userData.type="power"; g.userData.ring=ring;
  }
  g.traverse(o=>{ if(o.isMesh){ o.castShadow=true; } });
  return g;
}


/* ---------- Echte CC0-Obstacle-Modelle (assets/obstacles.glb, Quaternius/CC0) ---------- */
let obsTpl=null;
(function loadObstacles(){
  try{
    const el=document.getElementById("obstacledata");
    if(!el || typeof THREE.GLTFLoader==="undefined") return;
    const b64=(el.textContent||"").trim();
    if(b64.length<200 || b64.indexOf("__OBS")===0) return;
    const bin=atob(b64), buf=new Uint8Array(bin.length);
    for(let i=0;i<bin.length;i++) buf[i]=bin.charCodeAt(i);
    const loader=new THREE.GLTFLoader();
    if(THREE.DRACOLoader){ const d=new THREE.DRACOLoader(); d.setDecoderPath("https://unpkg.com/three@0.128.0/examples/js/libs/draco/"); loader.setDRACOLoader(d); }
    loader.parse(buf.buffer,"",gltf=>{
      obsTpl=gltf.scene;
      // bisher prozedural gepoolte Hindernisse verwerfen -> ab jetzt echte Modelle
      for(const k of ["crate","slide","wreck","train"]){ if(pools[k]){ pools[k].forEach(o=>scene.remove(o)); pools[k].length=0; } }
    }, ()=>{});
  }catch(e){}
})();
// Klon eines benannten Modells aus obsTpl (oder jungleTpl für Felsen)
function obsRaw(name){
  const src=(obsTpl&&obsTpl.getObjectByName(name)) || (jungleTpl&&jungleTpl.getObjectByName(name));
  if(!src) return null;
  const o=src.clone(true); o.traverse(m=>{ if(m.isMesh) o.castShadow=true; }); return o;
}
// Klon + gleichmäßig auf Zielhöhe skalieren + Füße auf y=0
function obsModel(name,targetH){
  const o=obsRaw(name); if(!o) return null;
  const b=new THREE.Box3().setFromObject(o); const h=(b.max.y-b.min.y)||1; const s=targetH/h;
  o.scale.setScalar(s);
  const b2=new THREE.Box3().setFromObject(o); o.position.y-=b2.min.y;
  return o;
}
const CRATE_NAMES=["crate1","crate2","crate3","barrel"];
const rnd=a=>a[(Math.random()*a.length)|0];
function glowRing(color,r){ const m=new THREE.Mesh(new THREE.TorusGeometry(r||0.95,0.07,8,24), new THREE.MeshBasicMaterial({color,transparent:true,opacity:.85})); m.rotation.x=Math.PI/2; m.position.y=0.07; return m; }

function buildObstacle(type){
  // Fallback auf prozedural, solange Modelle nicht geladen sind oder für Münzen/Power-Ups
  if(!obsTpl || type==="coin" || type==="power") return buildObstacleProc(type);
  const g=new THREE.Group();
  if(type==="crate"){
    // 1–2 echte Kisten/Fässer nebeneinander, niedrig (~1.25, überspringbar) + GELBER Marker
    const n=Math.random()<0.5?2:1;
    for(let i=0;i<n;i++){ const c=obsModel(rnd(CRATE_NAMES),1.25);
      if(c){ c.position.x=(n===2?(i?0.6:-0.6):0); c.rotation.y=Math.random()*6.28; g.add(c);} }
    g.add(glowRing(0xffd400,1.0));
    const ar=makeArrow(true); ar.position.set(0,2.0,0); g.add(ar);
    g.userData={type:"crate",halfZ:0.6,clear:"jump",arrowMesh:ar};
  } else if(type==="slide"){
    // echter Log-Querbalken auf 2 Holzposten, Unterkante ~1.95 + CYAN Marker
    const post=new THREE.Mesh(new THREE.BoxGeometry(0.22,2.3,0.22),M.woodDark);
    const p1=post.clone(); p1.position.set(-1.08,1.15,0); g.add(p1);
    const p2=post.clone(); p2.position.set(1.08,1.15,0); g.add(p2);
    const bar=obsRaw("log");
    if(bar){ bar.scale.setScalar(0.72); bar.position.set(0,1.95,0); g.add(bar); }  // log liegt entlang X (über die Spuren)
    else { const b=new THREE.Mesh(new THREE.CylinderGeometry(0.4,0.4,2.3,12),M.slideC); b.rotation.z=Math.PI/2; b.position.y=2.35; g.add(b); }
    const glow=new THREE.Mesh(new THREE.BoxGeometry(2.3,0.24,0.6),M.slideC); glow.position.y=2.0; g.add(glow);
    const ar=makeArrow(false); ar.position.set(0,0.9,0); g.add(ar);
    g.userData={type:"slide",halfZ:0.42,clear:"slide",arrowMesh:ar};
  } else if(type==="wreck"){
    // VARIANZ: Tiki-Maske / Kistenstapel / großer Fels — volle Sperre + ROTER Marker
    const pick=Math.random();
    if(pick<0.4){ const t=obsModel("tiki",2.0); if(t){ t.rotation.y=Math.PI; g.add(t);} }       // Maske blickt zur Kamera
    else if(pick<0.72){
      const a=obsModel(rnd(CRATE_NAMES),1.1), b=obsModel(rnd(CRATE_NAMES),1.0), c=obsModel(rnd(CRATE_NAMES),0.95);
      if(a){a.position.set(-0.35,0,0);g.add(a);} if(b){b.position.set(0.5,0,0.1);g.add(b);} if(c){c.position.set(0.0,1.1,0);g.add(c);}
    } else { const r=obsModel(rnd(["rock1","rock2","rock3","rock4"]),1.8); if(r){ r.rotation.y=Math.random()*6.28; g.add(r);} }
    const warn=new THREE.Mesh(new THREE.BoxGeometry(1.5,0.34,0.12),M.danger); warn.position.set(0,0.28,0.72); g.add(warn);
    g.add(glowRing(0xff1a0a,1.05));
    g.userData={type:"wreck",halfZ:0.7,clear:"dodge"};
  } else if(type==="train"){
    // langer echter Baumstamm quer über die Strecke (Z), lange Spursperre + roter Streifen
    const len=12;
    const log=obsRaw("log");
    if(log){ log.rotation.y=Math.PI/2; log.scale.set(len/3.77,1.8,1.8); log.position.y=0; g.add(log); }  // Ursprung=Unterkante -> y=0 liegt am Boden
    else { const l=new THREE.Mesh(new THREE.CylinderGeometry(1.0,1.0,len,14),M.bark); l.rotation.x=Math.PI/2; l.position.y=1.0; g.add(l); }
    const s1=new THREE.Mesh(new THREE.BoxGeometry(2.4,0.5,len),M.danger); s1.position.y=1.95; g.add(s1);
    g.userData={type:"train",halfZ:len/2,clear:"dodge"};
  }
  g.traverse(o=>{ if(o.isMesh) o.castShadow=true; });
  return g;
}

/* ===================================================================== */
/*  DSCHUNGEL-KULISSE (dicht, beidseitig, mehrlagig)                      */
/* ===================================================================== */
const scenActive=[];
let jungleTpl=null;                 // gltf.scene mit benannten Quaternius-Objekten (palm1.., tree1.., ...)
const SCEN_SCALE=1.5;               // Quaternius-Modelle (CC0) auf Spielgröße bringen
const scenPools={};                 // modelName -> [Klone]
// Platzierungs-Kategorien (Roh-Modelle: Quaternius "Ultimate Stylized Nature Pack", CC0, via poly.pizza)
const SCEN_NEAR=["bush1","bush2","bush3","plant1","plant2","flower1","flower2","flower3","grass1","grass2","rock1","rock2","rock3","rock4","dead2","palm3"];
const SCEN_BIG =["tree1","tree2","tree3","palm1","palm2","dead1"];
function acquireScen(name){
  let p=scenPools[name]||(scenPools[name]=[]);
  let o=p.find(m=>!m.visible);
  if(!o){
    if(!jungleTpl) return null;
    const src=jungleTpl.getObjectByName(name); if(!src) return null;
    o=src.clone(true);
    o.traverse(m=>{ if(m.isMesh){ m.castShadow=false; m.receiveShadow=false; } });
    scene.add(o); p.push(o);
  }
  o.visible=true; return o;
}
let scenAcc=0;
function place(name,x,z,sMin,sMax){
  const o=acquireScen(name); if(!o) return;
  o.position.set(x,0,z); o.rotation.y=Math.random()*6.283;
  o.scale.setScalar(SCEN_SCALE*(sMin+Math.random()*(sMax-sMin)));
  scenActive.push(o);
}
const pickNear=()=>SCEN_NEAR[(Math.random()*SCEN_NEAR.length)|0];
const pickBig =()=>SCEN_BIG[(Math.random()*SCEN_BIG.length)|0];
function spawnScenBand(z){
  if(!jungleTpl) return;
  for(const side of [-1,1]){
    place(pickNear(), side*(4.4+Math.random()*2.0), z+(Math.random()-.5)*3, 0.8,1.2);
    if(Math.random()<0.9) place(pickNear(), side*(6.6+Math.random()*2.6), z+(Math.random()-.5)*4, 0.85,1.25);
    if(Math.random()<0.8) place(Math.random()<.5?pickNear():pickBig(), side*(9.5+Math.random()*3.0), z+(Math.random()-.5)*5, 0.9,1.3);
    if(Math.random()<0.9) place(pickBig(), side*(13.5+Math.random()*9), z+(Math.random()-.5)*6, 1.0,1.5);
  }
}
// jungle.glb (Draco) laden -> jungleTpl, dann Kulisse vorbefüllen
(function loadJungle(){
  try{
    const el=document.getElementById("jungledata");
    if(!el || typeof THREE.GLTFLoader==="undefined") return;
    const b64=(el.textContent||"").trim();
    if(b64.length<200 || b64.indexOf("__JUNGLE")===0) return;
    const bin=atob(b64), buf=new Uint8Array(bin.length);
    for(let i=0;i<bin.length;i++) buf[i]=bin.charCodeAt(i);
    const loader=new THREE.GLTFLoader();
    if(THREE.DRACOLoader){ const d=new THREE.DRACOLoader(); d.setDecoderPath("https://unpkg.com/three@0.128.0/examples/js/libs/draco/"); loader.setDRACOLoader(d); }
    loader.parse(buf.buffer, "", gltf=>{
      jungleTpl=gltf.scene;
      // Kulisse (neu) befüllen
      scenActive.forEach(s=>s.visible=false); scenActive.length=0; scenAcc=0;
      for(let zz=-150; zz<-10; zz+=3.0) spawnScenBand(zz);
    }, ()=>{});
  }catch(e){}
})();

function updateScenery(dz){
  scenAcc+=dz;
  if(scenAcc>3.0){ scenAcc=0; spawnScenBand(-150); }   // dichtere Bänder (vorher 4.2)
  for(let i=scenActive.length-1;i>=0;i--){ const o=scenActive[i]; o.position.z+=dz;
    if(o.position.z>26){ o.visible=false; scenActive.splice(i,1); } }
}

/* ---------- Sonnen-Glanz Partikel (Pollen/Funkeln) ---------- */
const EMB=isMobile?120:220;
const embGeo=new THREE.BufferGeometry();
const embPos=new Float32Array(EMB*3), embVel=new Float32Array(EMB);
for(let i=0;i<EMB;i++){
  embPos[i*3]=(Math.random()-.5)*70;
  embPos[i*3+1]=Math.random()*16;
  embPos[i*3+2]=-Math.random()*120+10;
  embVel[i]=0.3+Math.random()*0.8;
}
embGeo.setAttribute("position",new THREE.BufferAttribute(embPos,3));
const embTex=(function(){ const c=document.createElement("canvas");c.width=c.height=32;const x=c.getContext("2d");
  const g=x.createRadialGradient(16,16,0,16,16,16); g.addColorStop(0,"rgba(255,255,220,1)");g.addColorStop(.4,"rgba(255,240,180,.7)");g.addColorStop(1,"rgba(255,240,180,0)");
  x.fillStyle=g;x.fillRect(0,0,32,32); return new THREE.CanvasTexture(c); })();
const embMat=new THREE.PointsMaterial({size:0.35,map:embTex,transparent:true,blending:THREE.AdditiveBlending,depthWrite:false,opacity:.7});
const embers=new THREE.Points(embGeo,embMat); scene.add(embers);

/* ===================================================================== */
/*  SPIELLOGIK                                                            */
/* ===================================================================== */
const G={
  state:"menu",        // menu | play | dead | pause
  speed:10, baseSpeed:10, maxSpeed:28,
  dist:0, score:0, coins:0, hi:+(localStorage.getItem(HI_KEY)||0),
  lane:1, targetX:0,
  y:0, vy:0, onGround:true, sliding:false, slideT:0,
  obstacles:[], coinObjs:[], powers:[],
  spawnAcc:0, sinceTrain:0, lastAction:null, trainHold:0, trainLane:0,
  runT:0, camShake:0, diff:0,
  // Power-Ups
  magnet:0, shield:0, jet:0,
  sound:true,
};
elHi.textContent=Math.floor(G.hi);

/* ---------- Audio (WebAudio, simpel) ---------- */
let AC=null;
function ac(){ if(!AC){ try{ AC=new (window.AudioContext||window.webkitAudioContext)(); }catch(e){} } return AC; }
function beep(freq,dur,type,vol){
  if(!G.sound) return; const a=ac(); if(!a) return;
  const o=a.createOscillator(), gn=a.createGain();
  o.type=type||"square"; o.frequency.value=freq;
  gn.gain.value=vol||0.06; o.connect(gn); gn.connect(a.destination);
  const t=a.currentTime; o.start(t);
  gn.gain.setValueAtTime(gn.gain.value,t); gn.gain.exponentialRampToValueAtTime(0.0001,t+dur);
  o.frequency.exponentialRampToValueAtTime(Math.max(40,freq*0.6),t+dur);
  o.stop(t+dur+0.02);
}
const sfx={
  jump:()=>beep(420,0.18,"square",0.05),
  slide:()=>beep(220,0.2,"sawtooth",0.05),
  coin:()=>beep(880,0.08,"triangle",0.05),
  power:()=>{beep(540,0.1,"triangle",0.06);setTimeout(()=>beep(820,0.14,"triangle",0.06),80);},
  hit:()=>{beep(120,0.4,"sawtooth",0.12);},
  shield:()=>beep(300,0.25,"square",0.08),
};

/* ---------- Spawning ----------
   Fairness-Regeln (immer lösbar):
   - max. 2 von 3 Spuren in einer Ausweich-Reihe belegt -> immer eine frei.
   - Volle-Breite-Reihen NUR rein springbar (Kisten) ODER rein rutschbar (Stämme).
   - Nach jeder Pflicht-Aktion folgt eine ruhige Ausweich-Reihe (Reaktionszeit).
   - Während ein Stamm rollt: nur Früchte, damit er allein bleibt.
   SCHWIERIGKEIT: G.diff wächst mit der Strecke OHNE Plateau und erhöht
   Hindernis-Dichte (mehr 2er-Reihen), Aktions-/Stamm-Häufigkeit. Reaktions-
   zeit bleibt fair, weil der Abstand mit dem Tempo skaliert (gap ∝ speed). */
const OBST_TYPES=["crate","slide","wreck"];
function dodgeRow(z){
  // 1–2 Hindernisse, immer mind. eine freie Spur. 2er-Chance wächst mit diff.
  const two = Math.random() < (0.20 + G.diff*0.28);
  const n = two?2:1;
  const lanes=[0,1,2]; shuffle(lanes);
  const used=[];
  for(let i=0;i<n;i++){
    const t=OBST_TYPES[(Math.random()*OBST_TYPES.length)|0];
    placeObstacle(t,lanes[i],z); used.push(lanes[i]);
  }
  const freeLanes=[0,1,2].filter(l=>!used.includes(l));
  if(freeLanes.length){
    const fl=freeLanes[(Math.random()*freeLanes.length)|0];
    if(Math.random()<0.72) spawnCoinLine(fl,z,4+(Math.random()*3|0));
    if(Math.random()<0.12) placePower(freeLanes[(Math.random()*freeLanes.length)|0],z-3);
  }
}
function spawnRow(){
  const z=-148;
  // Während ein Stamm rollt: nur Früchte (auf freier Spur)
  if(G.trainHold>0){ G.trainHold--; const free=[0,1,2].filter(l=>l!==G.trainLane);
    spawnCoinLine(free[(Math.random()*free.length)|0], z, 5); return; }
  // Nach einer Aktions-Reihe IMMER eine ruhige Ausweich-Reihe
  if(G.lastAction){ G.lastAction=null; G.sinceTrain++; dodgeRow(z); return; }

  const r=Math.random();
  const fullJump=0.05+G.diff*0.035;          // alle 3 Kisten -> springen
  const fullSlide=fullJump+0.05+G.diff*0.035; // alle 3 Stämme -> rutschen
  if(r<fullJump){
    for(let l=0;l<3;l++) placeObstacle("crate",l,z);
    spawnCoinArc(1,z-2.5,true); G.lastAction="jump"; G.sinceTrain++; return;
  }
  if(r<fullSlide){
    for(let l=0;l<3;l++) placeObstacle("slide",l,z);
    spawnCoinLine((Math.random()*3)|0, z-1, 3); G.lastAction="slide"; G.sinceTrain++; return;
  }
  // rollender Stamm gelegentlich (Häufigkeit wächst mit diff)
  G.sinceTrain++;
  if(G.sinceTrain>4 && Math.random() < (0.13+G.diff*0.10)){
    const lane=(Math.random()*3)|0;
    placeObstacle("train",lane,z-6);
    G.sinceTrain=0; G.trainLane=lane; G.trainHold=2;
    const free=[0,1,2].filter(l=>l!==lane);
    spawnCoinLine(free[(Math.random()*free.length)|0], z, 6);
    return;
  }
  dodgeRow(z);
}
function placeObstacle(type,lane,z){
  const o=acquire(type); o.position.set(LANE_X[lane],0,z); o.rotation.set(0,0,0);
  o.userData.lane=lane; o.userData.dead=false;
  G.obstacles.push(o);
}
function placePower(lane,z){
  const o=acquire("power"); o.position.set(LANE_X[lane],1.4,z);
  const kinds=["magnet","shield","jet"]; o.userData.kind=kinds[(Math.random()*kinds.length)|0];
  o.userData.lane=lane; o.userData.dead=false;
  G.powers.push(o);
}
function spawnCoinLine(lane,z,count){
  for(let i=0;i<count;i++){ const c=acquire("coin"); c.position.set(LANE_X[lane],1.1,z-i*1.6); c.userData.lane=lane; c.userData.dead=false; G.coinObjs.push(c); }
}
function spawnCoinArc(lane,z,jump){
  for(let i=0;i<7;i++){ const c=acquire("coin"); const t=i/6; const y= jump? 1.1+Math.sin(t*Math.PI)*2.0 : 1.1;
    c.position.set(LANE_X[lane],y,z-i*1.5); c.userData.lane=lane; c.userData.dead=false; G.coinObjs.push(c); }
}
function shuffle(a){ for(let i=a.length-1;i>0;i--){ const j=(Math.random()*(i+1))|0; [a[i],a[j]]=[a[j],a[i]]; } }

/* ---------- Steuerung ---------- */
function moveLane(dir){
  if(G.state!=="play") return;
  const nl=Math.max(0,Math.min(2,G.lane+dir));
  if(nl!==G.lane){ G.lane=nl; G.targetX=LANE_X[nl]; }
}
function jump(){
  if(G.state!=="play") return;
  if(G.onGround && !G.sliding){ G.vy=12.5; G.onGround=false; sfx.jump(); }
}
function slide(){
  if(G.state!=="play") return;
  if(!G.sliding){ G.sliding=true; G.slideT=0.62; if(!G.onGround){ G.vy=-16; } sfx.slide(); }
}

addEventListener("keydown",e=>{
  const k=e.key.toLowerCase();
  if(["arrowleft","a"].includes(k)){ moveLane(-1); e.preventDefault(); }
  else if(["arrowright","d"].includes(k)){ moveLane(1); e.preventDefault(); }
  else if(["arrowup","w"," ","spacebar"].includes(k)){ jump(); e.preventDefault(); }
  else if(["arrowdown","s"].includes(k)){ slide(); e.preventDefault(); }
  else if(k==="p"){ togglePause(); }
  else if(k==="m"){ toggleSound(); }
  else if(k==="escape"){ if(G.state==="play"||G.state==="pause") toMenu(); }
});

// Touch / Swipe
const touchEl=$("touch");
let tsx=0,tsy=0,tst=0;
function tStart(x,y){ tsx=x;tsy=y;tst=performance.now(); }
function tEnd(x,y){
  const dx=x-tsx, dy=y-tsy, adx=Math.abs(dx), ady=Math.abs(dy);
  if(adx<24 && ady<24){ jump(); return; } // Tap = Sprung
  if(adx>ady){ moveLane(dx>0?1:-1); } else { if(dy>0) slide(); else jump(); }
}
touchEl.addEventListener("touchstart",e=>{ const t=e.changedTouches[0]; tStart(t.clientX,t.clientY); },{passive:true});
touchEl.addEventListener("touchend",e=>{ const t=e.changedTouches[0]; tEnd(t.clientX,t.clientY); },{passive:true});
let pdown=false;
canvas.addEventListener("pointerdown",e=>{ if(G.state==="play"){ pdown=true; tStart(e.clientX,e.clientY);} });
canvas.addEventListener("pointerup",e=>{ if(pdown){ pdown=false; tEnd(e.clientX,e.clientY);} });

/* ---------- Charakter-Auswahl UI ---------- */
function charFaceCSS(key,cfg){
  const hood="#"+cfg.hoodie.toString(16).padStart(6,"0");
  const img=PORTRAITS[key];
  // Echtes 3D-Portrait oben drauf, dahinter ein zum Charakter passender Farb-Glow
  // (für die transparenten Bildbereiche).
  if(img){
    return `background-image:url('${img}'),
      radial-gradient(circle at 50% 38%, ${hood} 0%, #0c2b1e 78%);`;
  }
  // Fallback (kein Portrait eingebettet): altes Farbschema
  const skin="#"+cfg.skin.toString(16).padStart(6,"0");
  const cap ="#"+cfg.cap.toString(16).padStart(6,"0");
  return `background:
    radial-gradient(circle at 50% 118%, ${hood} 0 42%, transparent 43%),
    radial-gradient(circle at 50% 52%, ${skin} 0 30%, transparent 31%),
    linear-gradient(180deg, ${cap} 0 34%, transparent 34%),
    #173a2c;`;
}
function renderCharSel(){
  let h="";
  for(const key in CHARS){ const cfg=CHARS[key];
    h+=`<div class="char ${key===heroCfgKey?'sel':''}" data-char="${key}">
      <div class="face" style="${charFaceCSS(key,cfg)}"></div>
      <div class="nm">${cfg.name}</div><div class="ro">${cfg.role}</div></div>`;
  }
  charsel.innerHTML=h;
  charsel.querySelectorAll(".char").forEach(el=>{
    el.addEventListener("click",()=>{ setCharacter(el.dataset.char); sfx.coin(); });
  });
}

/* ---------- UI / Zustände ---------- */
function showOverlay(html,subHtml,btnLabel,showChars){
  ov.querySelector(".logo").innerHTML=html;
  ovsub.innerHTML=subHtml;
  startBtn.textContent=btnLabel;
  charsel.classList.toggle("hide",!showChars);
  ov.classList.remove("hide");
}
function hideOverlay(){ ov.classList.add("hide"); }

function startGame(){
  releaseAll();
  G.obstacles.length=0; G.coinObjs.length=0; G.powers.length=0;
  scenActive.forEach(s=>s.visible=false); scenActive.length=0; scenAcc=0;
  // Insel-Vorlauf: ein paar Bänder vorab platzieren, damit's nicht leer startet
  for(let zz=-150; zz<-10; zz+=3.0) spawnScenBand(zz);
  G.state="play"; G.speed=G.baseSpeed; G.dist=0; G.score=0; G.coins=0; G.diff=0;
  G.lane=1; G.targetX=0; G.y=0; G.vy=0; G.onGround=true; G.sliding=false; G.slideT=0;
  G.spawnAcc=0; G.sinceTrain=99; G.lastAction=null; G.trainHold=0; G.magnet=0; G.shield=0; G.jet=0; G.camShake=0;
  hero.position.set(0,0,0); hero.rotation.set(0,0,0); hero.scale.set(1,1,1);
  hero.userData.flame.visible=false;
  updateHud(); renderPups();
  hideOverlay();
  if(AC && AC.state==="suspended") AC.resume();
  ac();
}
function gameOver(){
  G.state="dead"; sfx.hit(); window.dispatchEvent(new CustomEvent('cfgame:final',{detail:{score:Math.floor(G.score)}}));
  G.camShake=0.6;
  let rec="";
  if(Math.floor(G.score)>Math.floor(G.hi)){ G.hi=G.score; localStorage.setItem(HI_KEY,Math.floor(G.hi)); rec='<div class="newrec">★ NEUER REKORD! ★</div>'; }
  elHi.textContent=Math.floor(G.hi);
  showOverlay('AUTSCH!<small>CRAZYFAMILY ARCADE</small>',
    rec+`<div class="stat"><div><span class="n">${Math.floor(G.score)}</span><span class="l">SCORE</span></div>`+
    `<div><span class="n">${G.coins}</span><span class="l">FRÜCHTE</span></div>`+
    `<div><span class="n">${Math.floor(G.dist)}m</span><span class="l">STRECKE</span></div></div>`,
    "▶ NOCHMAL", false);
  ovhint.style.display="";
}
function toMenu(){
  G.state="menu";
  showOverlay('CRAZY&nbsp;RUSH<small>CRAZYFAMILY ARCADE</small>',
    "Renn so weit du kannst durch den Dschungel der CrazyFamily-Insel – weiche aus, spring über Kisten, rutsch unter Stämmen durch und sammle leuchtende Früchte!",
    "▶ LOSLAUFEN", true);
}
function togglePause(){
  if(G.state==="play"){ G.state="pause"; showOverlay('PAUSE<small>CRAZYFAMILY ARCADE</small>',"Kurz verschnaufen…","▶ WEITER",false); }
  else if(G.state==="pause"){ G.state="play"; hideOverlay(); }
}
function toggleSound(){ G.sound=!G.sound; $("soundBtn").textContent=G.sound?"🔊":"🔇"; }

startBtn.addEventListener("click",()=>{
  if(G.state==="menu"||G.state==="dead") startGame();
  else if(G.state==="pause"){ G.state="play"; hideOverlay(); }
});
$("pauseBtn").addEventListener("click",togglePause);
$("soundBtn").addEventListener("click",toggleSound);

function updateHud(){
  elScore.textContent=Math.floor(G.score);
  elCoins.textContent=G.coins;
}
const PUP_INFO={magnet:{em:"🧲",name:"MAGNET"},shield:{em:"🛡️",name:"SCHILD"},jet:{em:"🚀",name:"JETPACK"}};
function renderPups(){
  let h="";
  if(G.magnet>0) h+=pupTag("magnet",G.magnet);
  if(G.shield>0) h+=`<div class="pup"><span class="em">${PUP_INFO.shield.em}</span><b>SCHILD</b></div>`;
  if(G.jet>0) h+=pupTag("jet",G.jet);
  elPups.innerHTML=h;
}
function pupTag(k,t){ return `<div class="pup"><span class="em">${PUP_INFO[k].em}</span><b>${PUP_INFO[k].name}</b> ${t.toFixed(1)}s</div>`; }

/* ---------- Kollision ---------- */
function checkHit(o){
  const hz=o.userData.halfZ||0.5;
  if(Math.abs(o.position.z) > (hz+0.55)) return false;
  if(o.userData.lane!==G.lane) return false;
  const clear=o.userData.clear;
  if(G.jet>0) return false; // drüber fliegen
  if(clear==="jump"){ return !(G.y>0.5); }   // springt drüber
  if(clear==="slide"){ return !G.sliding; }   // muss rutschen
  return true; // dodge: gleiche Spur = Treffer
}

/* ---------- Power-Up aktivieren ---------- */
function activatePower(kind){
  sfx.power();
  if(kind==="magnet") G.magnet=8;
  else if(kind==="shield") G.shield=1;
  else if(kind==="jet"){ G.jet=4.2; }
}

/* ---------- Hauptschleife ---------- */
let last=performance.now();
function loop(now){
  requestAnimationFrame(loop);
  let dt=(now-last)/1000; last=now;
  if(dt>0.05) dt=0.05;

  const playing=G.state==="play";
  animateEmbers(dt, playing);
  // Wolken driften immer
  for(const cl of clouds){ cl.position.x+=cl.userData.drift*dt; if(cl.position.x>180) cl.position.x=-180; }

  if(playing){
    // Schwierigkeit eskaliert über eine LANGE Strecke (kein frühes Plateau):
    // diff wächst bis ~4800 m weiter und steuert Tempo, Dichte & Aktions-Häufigkeit.
    G.diff=Math.min(1.6, G.dist/3000);
    // Tempo klettert kontinuierlich; Beschleunigung steigt mit diff
    G.speed=Math.min(G.maxSpeed, G.speed + dt*(0.22 + G.diff*0.16));
    const dz=G.speed*dt;
    G.dist+=dz; G.score+=dz*1.0;
    // Boden-Texturen exakt zur Welt-Bewegung scrollen (sonst „Laufband"-Effekt):
    // Straße: gleichförmiger Asphalt, 1 Kachel = 360/2 = 180 E. -> dz/180 (Scroll ohnehin
    // kaum sichtbar mangels Quermerkmalen). Gras: 360/30 = 12 -> dz/12.
    roadTex.offset.y -= dz/180;
    grassTex.offset.y -= dz/12;

    // Spawn — Abstand ∝ Tempo (faire, ~konstante Reaktionszeit),
    // mit zunehmender Verdichtung über diff
    G.spawnAcc+=dz;
    const gap=Math.max(9, G.speed*(0.62 - G.diff*0.05));
    if(G.spawnAcc>=gap){ G.spawnAcc=0; spawnRow(); }
    updateScenery(dz);

    moveAndCull(G.obstacles,dz);
    moveAndCull(G.coinObjs,dz);
    moveAndCull(G.powers,dz);

    // Held: Spurwechsel
    hero.position.x += (G.targetX-hero.position.x)*Math.min(1,dt*14);
    // Sprung / Jetpack
    if(G.jet>0){
      G.jet-=dt;
      const targetY=4.2; G.y += (targetY-G.y)*Math.min(1,dt*6);
      G.vy=0; G.onGround=false; hero.userData.flame.visible=true;
      if(G.jet<=0){ hero.userData.flame.visible=false; }
    } else {
      G.vy-=34*dt; G.y+=G.vy*dt;
      if(G.y<=0){ G.y=0; G.vy=0; G.onGround=true; }
      hero.userData.flame.visible=false;
    }
    hero.position.y=G.y;
    // Rutschen
    if(G.sliding){ G.slideT-=dt; if(G.slideT<=0) G.sliding=false; }
    if(hero.userData.mixer){
      // gerigtes Modell: Slide-Clip duckt schon, ABER die Figur (Scale 1.5) ist hoch -> beim
      // Rutschen zusätzlich nach vorn kippen + stauchen, damit sie sichtbar UNTER den Balken passt.
      const sScale=G.sliding?0.58:1, sTilt=G.sliding?-0.55:0;
      hero.scale.y += (sScale-hero.scale.y)*Math.min(1,dt*16);
      hero.rotation.x += (sTilt-hero.rotation.x)*Math.min(1,dt*16);
    } else {
      const slideScale=G.sliding?0.5:1;
      hero.scale.y += (slideScale-hero.scale.y)*Math.min(1,dt*16);
      hero.rotation.x = G.sliding? -0.5 : 0;
    }

    animateHero(dt);

    if(G.magnet>0) G.magnet=Math.max(0,G.magnet-dt);
    // Magnet zieht Früchte
    if(G.magnet>0){
      for(const c of G.coinObjs){ if(c.userData.dead) continue;
        const dx=hero.position.x-c.position.x, dy=(hero.position.y+1)-c.position.y, dz2=hero.position.z-c.position.z;
        if(Math.abs(dz2)<14 && Math.abs(dx)<6){ c.position.x+=dx*Math.min(1,dt*7); c.position.y+=dy*Math.min(1,dt*7); c.userData.lane=G.lane; }
      }
    }
    // Früchte sammeln
    for(const c of G.coinObjs){ if(c.userData.dead) continue;
      c.rotation.y+=dt*3;
      const near=Math.abs(c.position.z)<1.0;
      const sameLane = c.userData.lane===G.lane || Math.abs(c.position.x-hero.position.x)<1.0;
      const yOk=Math.abs(c.position.y-(hero.position.y+1.1))<1.5 || G.jet>0 || G.magnet>0;
      if(near && sameLane && yOk){ c.userData.dead=true; c.visible=false; collectCoin(); }
    }
    // Power-Ups
    for(const p of G.powers){ if(p.userData.dead) continue;
      p.rotation.y+=dt*2; if(p.userData.ring) p.userData.ring.rotation.x+=dt*3;
      const near=Math.abs(p.position.z)<1.2;
      const sameLane=p.userData.lane===G.lane;
      if(near && sameLane){ p.userData.dead=true; p.visible=false; activatePower(p.userData.kind); }
    }
    // Hindernis-Kollision
    for(const o of G.obstacles){ if(o.userData.dead) continue;
      if(checkHit(o)){
        if(G.shield>0){ G.shield=0; sfx.shield(); o.userData.dead=true; o.visible=false; G.camShake=0.25; flashScreen(0.5); }
        else { gameOver(); break; }
      }
    }

    updateHud(); renderPups();
  } else {
    animateHero(dt,true);
  }

  updateCamera(dt);
  renderer.render(scene,camera);
}

function moveAndCull(arr,dz){
  for(let i=arr.length-1;i>=0;i--){ const o=arr[i]; o.position.z+=dz;
    if(o.userData.dead || o.position.z> (o.userData.halfZ||0.5)+14){ o.visible=false; arr.splice(i,1); }
  }
}
function collectCoin(){ G.coins++; G.score+=10; sfx.coin(); }

function setHeroAction(u, act){
  if(!act || u.cur===act) return;
  act.enabled=true; act.setEffectiveTimeScale(1); act.setEffectiveWeight(1); act.reset(); act.play();
  if(u.cur) act.crossFadeFrom(u.cur, 0.15, true);
  u.cur=act;
}
function animateHero(dt, idle){
  const u=hero.userData;
  // ---- gerigtes Meshy-Modell: Animations-Clips per Mixer ----
  if(u.mixer){
    u.mixer.update(dt);
    const playing=(G.state==="play" && !idle);
    let act=u.actions.Run;
    if(playing && G.sliding && u.actions.Slide) act=u.actions.Slide;
    else if(playing && !G.onGround && u.actions.Jump) act=u.actions.Jump;
    setHeroAction(u, act);
    if(act===u.actions.Run && u.actions.Run){
      // Lauf-Tempo an die Boden-Geschwindigkeit koppeln (kein Moonwalk), gedeckelt.
      u.actions.Run.timeScale = playing ? Math.min(2.2, 1.0 + G.speed*0.03) : 0.42;
    }
    if(!playing){ // im Menü/Tod sanft zentrieren
      hero.position.x += (0-hero.position.x)*Math.min(1,dt*8);
      hero.position.y += (0-hero.position.y)*Math.min(1,dt*8);
    }
    if(u.flame && u.flame.visible){ u._t=(u._t||0)+dt; u.flame.scale.y=1+Math.sin(u._t*5)*0.3; u.flame.material.opacity=0.7+Math.random()*0.3; }
    return;
  }
  // ---- prozeduraler Box-Held (Fallback) ----
  if(G.state==="play" && !idle){
    // Schritt-Frequenz an die echte Boden-Geschwindigkeit koppeln (kein Moonwalk),
    // nach oben gedeckelt, damit die Beine bei Topspeed nicht strobend flackern.
    G.runT += dt*Math.min(34, 7 + G.speed*0.95);
    const s=Math.sin(G.runT), c=Math.cos(G.runT);
    if(G.onGround && !G.sliding){
      u.legL.rotation.x=s*0.9; u.legR.rotation.x=-s*0.9;
      u.armL.rotation.x=-s*0.8; u.armR.rotation.x=s*0.8;
      u.torso.rotation.z=c*0.04;
      hero.position.y=G.y+Math.abs(s)*0.06;
    } else if(G.sliding){
      u.legL.rotation.x=-0.7; u.legR.rotation.x=-0.7; u.armL.rotation.x=-1.4; u.armR.rotation.x=-1.4;
    } else {
      u.legL.rotation.x=-0.5; u.legR.rotation.x=0.4; u.armL.rotation.x=-1.6; u.armR.rotation.x=-1.6;
    }
    if(u.flame.visible){ u.flame.scale.y=1+Math.sin(G.runT*5)*0.3; u.flame.material.opacity=0.7+Math.random()*0.3; }
  } else {
    G.runT+=dt*3; const s=Math.sin(G.runT);
    u.armL.rotation.x=u.armR.rotation.x=s*0.1; u.legL.rotation.x=u.legR.rotation.x=0;
    u.torso.rotation.z=Math.sin(G.runT*0.5)*0.02;
    hero.position.set(0,Math.abs(s)*0.04,0);
  }
}

function updateCamera(dt){
  const tx=hero.position.x*0.45;
  camera.position.x += (tx-camera.position.x)*Math.min(1,dt*6);
  camera.position.y += (camBase.y - camera.position.y)*Math.min(1,dt*4);
  let sx=0,sy=0;
  if(G.camShake>0){ G.camShake-=dt; const m=G.camShake*1.4; sx=(Math.random()-.5)*m; sy=(Math.random()-.5)*m; }
  camera.position.x+=sx; camera.position.y+=sy;
  camera.lookAt(hero.position.x*0.5, 1.3+sy*0.5, -10);
  sunTarget.position.set(hero.position.x,0,-6);
  skyDome.position.set(camera.position.x,0,camera.position.z-100);
}

function animateEmbers(dt, playing){
  const p=embGeo.attributes.position.array;
  const adv=playing? G.speed*dt : 4*dt;
  for(let i=0;i<EMB;i++){
    p[i*3+1]+=embVel[i]*dt*0.4;
    p[i*3+2]+=adv;
    if(p[i*3+1]>18 || p[i*3+2]>14){
      p[i*3]=(Math.random()-.5)*70; p[i*3+1]=Math.random()*4; p[i*3+2]=-110-Math.random()*30;
    }
  }
  embGeo.attributes.position.needsUpdate=true;
}

function flashScreen(v){ flash.style.opacity=v; setTimeout(()=>{ flash.style.opacity=0; },90); }

/* ---------- Resize ---------- */
function resize(){
  const w=window.innerWidth, h=window.innerHeight;
  const dpr=window.devicePixelRatio||1;
  const maxBufW=isMobile?1280:1920;
  const ratio=Math.min(dpr, maxBufW/w, 2);
  renderer.setPixelRatio(ratio);
  renderer.setSize(w,h,false);
  camera.aspect=w/h; camera.updateProjectionMatrix();
}
addEventListener("resize",resize); resize();

/* ---------- Start ---------- */
renderCharSel();
// Insel-Deko schon im Menü zeigen
for(let zz=-150; zz<-10; zz+=3.0) spawnScenBand(zz);
toMenu();
requestAnimationFrame(loop);

})();
</script>

<!-- Bestenlisten-Overlay: erscheint bei Game Over (Event cfgame:final) oder per 🏆-Button.
     Globale Top 10 über die bestehende Highscore-API (assets/api/highscores.php). -->
<div id="cfBoard" hidden>
  <div class="lb-card">
    <h2 id="lbTitle">🏆 Bestenliste</h2>
    <p id="lbResult" hidden>Dein Ergebnis: <strong id="lbScore">0</strong></p>
    <div id="lbSubmitRow" hidden>
      <input type="text" id="lbNick" maxlength="16" placeholder="Dein Name" aria-label="Spitzname für die Bestenliste" />
      <button type="button" id="lbSubmit" class="lb-btn">Eintragen</button>
    </div>
    <ol id="lbList" aria-label="Globale Bestenliste"></ol>
    <div class="lb-actions">
      <button type="button" id="lbClose" class="lb-btn lb-btn--ghost">Schließen</button>
    </div>
  </div>
</div>

<script src="/assets/js/games/arcade.js" defer></script>
<script>
/* Highscore-Controller (globale Top 10 via highscores.php). Läuft nach dem defer-Skript.
   Das Spiel feuert bei Game Over window.dispatchEvent(new CustomEvent('cfgame:final',{detail:{score}})). */
document.addEventListener('DOMContentLoaded', function () {
  if (!window.CFArcade) return;
  var GAME = 'rush';

  var board     = document.getElementById('cfBoard');
  var title     = document.getElementById('lbTitle');
  var result    = document.getElementById('lbResult');
  var scoreEl   = document.getElementById('lbScore');
  var submitRow = document.getElementById('lbSubmitRow');
  var nick      = document.getElementById('lbNick');
  var submitBtn = document.getElementById('lbSubmit');
  var list      = document.getElementById('lbList');
  var pendingScore = 0;

  // Solange das Overlay offen ist, dürfen die Spieltasten (WASD/Pfeile/Enter/ESC/P/M)
  // NICHT beim Spiel landen -> Capture-Phase stoppt sie vor den Spiel-Listenern.
  ['keydown', 'keyup'].forEach(function (ev) {
    window.addEventListener(ev, function (e) {
      if (board.hidden) return;
      if (e.code === 'Escape' && ev === 'keydown') { e.stopPropagation(); closeBoard(); return; }
      e.stopPropagation();
      if (CFArcade.isTyping(e.target) && e.code === 'Enter' && ev === 'keydown') submit();
    }, true);
  });

  function renderBoard(scores) {
    if (!scores || !scores.length) {
      list.innerHTML = '<li class="lb-empty">Noch keine Einträge – sei der Erste!</li>';
      return;
    }
    list.innerHTML = scores.map(function (s, i) {
      return '<li><span class="lb-rank">' + (i + 1) + '.</span>' +
             '<span class="lb-name">' + s.name + '</span>' +
             '<span class="lb-score">' + s.score + '</span></li>';
    }).join('');
  }
  function refreshBoard() {
    list.innerHTML = '<li class="lb-empty">Lade…</li>';
    CFArcade.loadGlobal(GAME).then(renderBoard);
  }

  function openBoard(mode, score) {
    var over = mode === 'final';
    title.textContent = over ? '🏁 Game Over' : '🏆 Bestenliste';
    result.hidden = !over;
    if (over) {
      var record = CFArcade.setLocalBest(GAME, score);
      scoreEl.textContent = score + (record ? ' 🏆 Neuer Rekord!' : '');
      pendingScore = score;
    }
    submitRow.hidden = !(over && pendingScore > 0);
    submitBtn.disabled = false;
    submitBtn.textContent = 'Eintragen';
    nick.value = CFArcade.getNick();
    board.hidden = false;
    refreshBoard();
  }
  function closeBoard() { board.hidden = true; }

  function submit() {
    if (pendingScore <= 0 || submitBtn.disabled) return;
    var name = (nick.value || '').trim() || 'Anonym';
    CFArcade.setNick(name);
    submitBtn.disabled = true;
    submitBtn.textContent = 'Gesendet ✓';
    CFArcade.submitGlobal(GAME, name, pendingScore).then(renderBoard);
    pendingScore = 0;
    submitRow.hidden = true;
  }

  // Spielende -> Ergebnis-/Eintrag-Overlay (kurz den Game-Over-Sound wirken lassen)
  window.addEventListener('cfgame:final', function (e) {
    setTimeout(function () { openBoard('final', Math.floor(e.detail.score)); }, 900);
  });

  document.getElementById('boardBtn').addEventListener('click', function () {
    board.hidden ? openBoard('view') : closeBoard();
  });
  document.getElementById('lbClose').addEventListener('click', closeBoard);
  submitBtn.addEventListener('click', submit);
});
</script>

</body>
</html>
